function triggerShutters(bgUrl) {
  shuttersClosed.value = true;
  const openShutters = () => {
    setTimeout(() => { shuttersClosed.value = false; }, 900);
  };
  if (!bgUrl) { openShutters(); return; }
  const img = new Image();
  img.onload = openShutters;
  img.onerror = openShutters;
  img.src = bgUrl;
  // Safety timeout in case image stalls
  setTimeout(openShutters, 3000);
}

